#include<bits/stdc++.h>
using namespace std;
char a[101][101];
int n, maxans = 0;
bool b[101][101];
int dx[] = {1, 0, -1, 0};
int dy[] = {0, 1, 0, -1};
int dfs(int x, int y) {
	int ans = 1;
	b[x][y] = 1;
	for (int i = 0; i < 4; i++) {
		int mx = x + dx[i];
		int my = y + dy[i];
		if (mx >= 1 && my >= 1 && mx <= n && my <= n) {
			if (!b[mx][my] && a[mx][my] == 'A') {
				ans += dfs(mx, my);
			}
		}
	}

	return ans;
}
int main() {
	cin >> n;
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= n; j++) {
			cin >> a[i][j];
		}
	}
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= n; j++) {
			if (a[i][j] == 'B') {
				memset(b, 0, sizeof(b));
				int ans = dfs(i, j);
				//cout << ans << " ";
				maxans = max(maxans, ans);
			}
		}
	}
	cout<<maxans;
	return 0;
}
